import{_ as a,c as o,o as t,aj as r}from"./chunks/framework.BlveriQe.js";const u=JSON.parse('{"title":"Interface: WorkflowsAPI","description":"","frontmatter":{},"headers":[],"relativePath":"reference/js-bao-wss-client/api/interfaces/WorkflowsAPI.md","filePath":"reference/js-bao-wss-client/api/interfaces/WorkflowsAPI.md"}'),s={name:"reference/js-bao-wss-client/api/interfaces/WorkflowsAPI.md"};function l(n,e,i,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<p><a href="./../README.html"><strong>js-bao-wss-client</strong></a></p><hr><p><a href="./../globals.html">js-bao-wss-client</a> / WorkflowsAPI</p><h1 id="interface-workflowsapi" tabindex="-1">Interface: WorkflowsAPI <a class="header-anchor" href="#interface-workflowsapi" aria-label="Permalink to “Interface: WorkflowsAPI”">​</a></h1><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to “Methods”">​</a></h2><h3 id="claimapply" tabindex="-1">claimApply() <a class="header-anchor" href="#claimapply" aria-label="Permalink to “claimApply()”">​</a></h3><blockquote><p><strong>claimApply</strong>(<code>options</code>): <code>Promise</code>&lt;<a href="./ClaimApplyResult.html"><code>ClaimApplyResult</code></a>&gt;</p></blockquote><p>Claim a workflow result for client-side apply. Returns { claimed: true } if this client won the lock.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options" tabindex="-1">options <a class="header-anchor" href="#options" aria-label="Permalink to “options”">​</a></h5><p><a href="./ClaimApplyOptions.html"><code>ClaimApplyOptions</code></a></p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./ClaimApplyResult.html"><code>ClaimApplyResult</code></a>&gt;</p><hr><h3 id="confirmapply" tabindex="-1">confirmApply() <a class="header-anchor" href="#confirmapply" aria-label="Permalink to “confirmApply()”">​</a></h3><blockquote><p><strong>confirmApply</strong>(<code>options</code>): <code>Promise</code>&lt;<a href="./ConfirmApplyResult.html"><code>ConfirmApplyResult</code></a>&gt;</p></blockquote><p>Confirm that a claimed workflow result has been applied to the document.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-1" tabindex="-1">options <a class="header-anchor" href="#options-1" aria-label="Permalink to “options”">​</a></h5><p><a href="./ConfirmApplyOptions.html"><code>ConfirmApplyOptions</code></a></p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./ConfirmApplyResult.html"><code>ConfirmApplyResult</code></a>&gt;</p><hr><h3 id="define" tabindex="-1">define() <a class="header-anchor" href="#define" aria-label="Permalink to “define()”">​</a></h3><blockquote><p><strong>define</strong>(<code>workflowKey</code>, <code>options</code>): <code>void</code></p></blockquote><p>Define a workflow with its apply handler. Call once at app initialization so any client can handle apply.</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="workflowkey" tabindex="-1">workflowKey <a class="header-anchor" href="#workflowkey" aria-label="Permalink to “workflowKey”">​</a></h5><p><code>string</code></p><h5 id="options-2" tabindex="-1">options <a class="header-anchor" href="#options-2" aria-label="Permalink to “options”">​</a></h5><p><a href="./WorkflowDefineOptions.html"><code>WorkflowDefineOptions</code></a></p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to “Returns”">​</a></h4><p><code>void</code></p><hr><h3 id="getpendingapplies" tabindex="-1">getPendingApplies() <a class="header-anchor" href="#getpendingapplies" aria-label="Permalink to “getPendingApplies()”">​</a></h3><blockquote><p><strong>getPendingApplies</strong>(<code>options</code>): <code>Promise</code>&lt;<code>any</code>[]&gt;</p></blockquote><p>Fetch pending workflow applies for a document.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-3" tabindex="-1">options <a class="header-anchor" href="#options-3" aria-label="Permalink to “options”">​</a></h5><h6 id="contextdocid" tabindex="-1">contextDocId <a class="header-anchor" href="#contextdocid" aria-label="Permalink to “contextDocId”">​</a></h6><p><code>string</code></p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<code>any</code>[]&gt;</p><hr><h3 id="getstatus" tabindex="-1">getStatus() <a class="header-anchor" href="#getstatus" aria-label="Permalink to “getStatus()”">​</a></h3><blockquote><p><strong>getStatus</strong>&lt;<code>O</code>&gt;(<code>options</code>): <code>Promise</code>&lt;<a href="./WorkflowStatusResult.html"><code>WorkflowStatusResult</code></a>&lt;<code>O</code>&gt;&gt;</p></blockquote><p>Get the status of a workflow run. If contextDocId is not provided, uses the user&#39;s root document.</p><p>The optional generic <code>O</code> types the result envelope&#39;s <code>output</code> (issue #1512). It is additive and defaults to today&#39;s untyped <code>any</code>, so existing callers are unaffected. The generated per-workflow <code>&lt;key&gt;(client)</code> factory supplies it from the workflow&#39;s <code>outputSchema</code>.</p><h4 id="type-parameters" tabindex="-1">Type Parameters <a class="header-anchor" href="#type-parameters" aria-label="Permalink to “Type Parameters”">​</a></h4><h5 id="o" tabindex="-1">O <a class="header-anchor" href="#o" aria-label="Permalink to “O”">​</a></h5><p><code>O</code> = <code>any</code></p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-4" tabindex="-1">options <a class="header-anchor" href="#options-4" aria-label="Permalink to “options”">​</a></h5><p><a href="./GetWorkflowStatusOptions.html"><code>GetWorkflowStatusOptions</code></a></p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./WorkflowStatusResult.html"><code>WorkflowStatusResult</code></a>&lt;<code>O</code>&gt;&gt;</p><hr><h3 id="listruns" tabindex="-1">listRuns() <a class="header-anchor" href="#listruns" aria-label="Permalink to “listRuns()”">​</a></h3><blockquote><p><strong>listRuns</strong>(<code>options?</code>): <code>Promise</code>&lt;<a href="./ListWorkflowRunsResult.html"><code>ListWorkflowRunsResult</code></a>&gt;</p></blockquote><p>List workflow runs for the current user</p><h4 id="parameters-5" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-5" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-5" tabindex="-1">options? <a class="header-anchor" href="#options-5" aria-label="Permalink to “options?”">​</a></h5><p><a href="./ListWorkflowRunsOptions.html"><code>ListWorkflowRunsOptions</code></a></p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./ListWorkflowRunsResult.html"><code>ListWorkflowRunsResult</code></a>&gt;</p><hr><h3 id="liststepruns" tabindex="-1">listStepRuns() <a class="header-anchor" href="#liststepruns" aria-label="Permalink to “listStepRuns()”">​</a></h3><blockquote><p><strong>listStepRuns</strong>(<code>options</code>): <code>Promise</code>&lt;<a href="./ListWorkflowStepRunsResult.html"><code>ListWorkflowStepRunsResult</code></a>&gt;</p></blockquote><p>List step runs for a specific workflow run. The run must have been started by the current user.</p><h4 id="parameters-6" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-6" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-6" tabindex="-1">options <a class="header-anchor" href="#options-6" aria-label="Permalink to “options”">​</a></h5><p><a href="./ListWorkflowStepRunsOptions.html"><code>ListWorkflowStepRunsOptions</code></a></p><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./ListWorkflowStepRunsResult.html"><code>ListWorkflowStepRunsResult</code></a>&gt;</p><hr><h3 id="releaseapply" tabindex="-1">releaseApply() <a class="header-anchor" href="#releaseapply" aria-label="Permalink to “releaseApply()”">​</a></h3><blockquote><p><strong>releaseApply</strong>(<code>options</code>): <code>Promise</code>&lt;<a href="./ReleaseApplyResult.html"><code>ReleaseApplyResult</code></a>&gt;</p></blockquote><p>Release a claimed workflow apply so another client can retry. Called automatically on apply handler failure.</p><h4 id="parameters-7" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-7" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-7" tabindex="-1">options <a class="header-anchor" href="#options-7" aria-label="Permalink to “options”">​</a></h5><p><a href="./ReleaseApplyOptions.html"><code>ReleaseApplyOptions</code></a></p><h4 id="returns-7" tabindex="-1">Returns <a class="header-anchor" href="#returns-7" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./ReleaseApplyResult.html"><code>ReleaseApplyResult</code></a>&gt;</p><hr><h3 id="runsync" tabindex="-1">runSync() <a class="header-anchor" href="#runsync" aria-label="Permalink to “runSync()”">​</a></h3><blockquote><p><strong>runSync</strong>&lt;<code>I</code>, <code>O</code>&gt;(<code>options</code>): <code>Promise</code>&lt;<a href="./RunSyncWorkflowResult.html"><code>RunSyncWorkflowResult</code></a>&lt;<code>O</code>&gt;&gt;</p></blockquote><p>Synchronously invoke a workflow and wait for the final result.</p><p>Only callable on workflows marked <code>syncCallable: true</code> in their server-side definition (issue #728). Use this for low-latency, short-task workflows. Long-running workflows should keep using <code>start()</code> plus the WebSocket / polling lifecycle.</p><p>The promise <strong>resolves</strong> with the final envelope for every outcome, including engine failure and timeout — failure surfaces as <code>status: &quot;failed&quot;</code> (or <code>&quot;timeout&quot;</code> / <code>&quot;terminated&quot;</code>), not a thrown error. Network / transport errors still reject as usual.</p><p>The optional generics <code>I</code> (input) and <code>O</code> (<code>output</code>) type the payload and the result envelope (issue #1442). Both are additive and default to today&#39;s untyped <code>Record&lt;string, any&gt;</code> / <code>any</code>, so existing callers are unaffected. The generated per-workflow <code>&lt;key&gt;(client)</code> factory supplies them from the workflow&#39;s <code>inputSchema</code>/<code>outputSchema</code>.</p><h4 id="type-parameters-1" tabindex="-1">Type Parameters <a class="header-anchor" href="#type-parameters-1" aria-label="Permalink to “Type Parameters”">​</a></h4><h5 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to “I”">​</a></h5><p><code>I</code> = <code>Record</code>&lt;<code>string</code>, <code>any</code>&gt;</p><h5 id="o-1" tabindex="-1">O <a class="header-anchor" href="#o-1" aria-label="Permalink to “O”">​</a></h5><p><code>O</code> = <code>any</code></p><h4 id="parameters-8" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-8" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-8" tabindex="-1">options <a class="header-anchor" href="#options-8" aria-label="Permalink to “options”">​</a></h5><p><code>Omit</code>&lt;<a href="./RunSyncWorkflowOptions.html"><code>RunSyncWorkflowOptions</code></a>, <code>&quot;input&quot;</code>&gt; &amp; <code>object</code></p><h4 id="returns-8" tabindex="-1">Returns <a class="header-anchor" href="#returns-8" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./RunSyncWorkflowResult.html"><code>RunSyncWorkflowResult</code></a>&lt;<code>O</code>&gt;&gt;</p><hr><h3 id="start" tabindex="-1">start() <a class="header-anchor" href="#start" aria-label="Permalink to “start()”">​</a></h3><blockquote><p><strong>start</strong>&lt;<code>I</code>&gt;(<code>options</code>): <code>Promise</code>&lt;<a href="./StartWorkflowResult.html"><code>StartWorkflowResult</code></a>&gt;</p></blockquote><p>Start a workflow and return the run information.</p><p>The optional generic <code>I</code> types the <code>input</code> payload (issue #1442). It is additive and defaults to today&#39;s untyped <code>Record&lt;string, any&gt;</code>, so existing callers that pass no type argument are unaffected. The generated per-workflow <code>&lt;key&gt;(client)</code> factory (<code>primitive workflows codegen</code>) supplies it from the workflow&#39;s <code>inputSchema</code>.</p><h4 id="type-parameters-2" tabindex="-1">Type Parameters <a class="header-anchor" href="#type-parameters-2" aria-label="Permalink to “Type Parameters”">​</a></h4><h5 id="i-1" tabindex="-1">I <a class="header-anchor" href="#i-1" aria-label="Permalink to “I”">​</a></h5><p><code>I</code> = <code>Record</code>&lt;<code>string</code>, <code>any</code>&gt;</p><h4 id="parameters-9" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-9" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-9" tabindex="-1">options <a class="header-anchor" href="#options-9" aria-label="Permalink to “options”">​</a></h5><p><code>Omit</code>&lt;<a href="./StartWorkflowOptions.html"><code>StartWorkflowOptions</code></a>, <code>&quot;input&quot;</code>&gt; &amp; <code>object</code></p><h4 id="returns-9" tabindex="-1">Returns <a class="header-anchor" href="#returns-9" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./StartWorkflowResult.html"><code>StartWorkflowResult</code></a>&gt;</p><hr><h3 id="terminate" tabindex="-1">terminate() <a class="header-anchor" href="#terminate" aria-label="Permalink to “terminate()”">​</a></h3><blockquote><p><strong>terminate</strong>&lt;<code>O</code>&gt;(<code>options</code>): <code>Promise</code>&lt;<a href="./WorkflowStatusResult.html"><code>WorkflowStatusResult</code></a>&lt;<code>O</code>&gt;&gt;</p></blockquote><p>Terminate a running workflow. If contextDocId is not provided, uses the user&#39;s root document.</p><p>The optional generic <code>O</code> types the result envelope&#39;s <code>output</code> (issue #1512) — a terminated run can still carry partial output. Additive, defaults to <code>any</code>. Typed termination is available via this explicit generic; the generated factory intentionally does not emit a <code>terminate</code> member.</p><h4 id="type-parameters-3" tabindex="-1">Type Parameters <a class="header-anchor" href="#type-parameters-3" aria-label="Permalink to “Type Parameters”">​</a></h4><h5 id="o-2" tabindex="-1">O <a class="header-anchor" href="#o-2" aria-label="Permalink to “O”">​</a></h5><p><code>O</code> = <code>any</code></p><h4 id="parameters-10" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-10" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-10" tabindex="-1">options <a class="header-anchor" href="#options-10" aria-label="Permalink to “options”">​</a></h5><p><a href="./TerminateWorkflowOptions.html"><code>TerminateWorkflowOptions</code></a></p><h4 id="returns-10" tabindex="-1">Returns <a class="header-anchor" href="#returns-10" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./WorkflowStatusResult.html"><code>WorkflowStatusResult</code></a>&lt;<code>O</code>&gt;&gt;</p><hr><h3 id="waitfor" tabindex="-1">waitFor() <a class="header-anchor" href="#waitfor" aria-label="Permalink to “waitFor()”">​</a></h3><blockquote><p><strong>waitFor</strong>(<code>runId</code>, <code>options?</code>): <code>Promise</code>&lt;<a href="./WaitForWorkflowResult.html"><code>WaitForWorkflowResult</code></a>&gt;</p></blockquote><p>Wait for an async workflow run to reach a terminal state, then resolve <code>{ status, output?, error? }</code> (#1443).</p><p>Event-driven: it subscribes to the existing <code>workflowStatus</code> WebSocket frame and issues no polling. One reconcile fetch runs immediately after subscribing to close the started-before-subscribed race (the terminal frame is only delivered to live connections and is not replayed). On a WS reconnect it re-runs that single reconcile fetch — still no interval timer.</p><p>Resolves on every terminal state, including workflow failure (<code>status: &quot;failed&quot;</code>) — a failing run does NOT reject. It also treats a run with <code>endedAt</code> set as terminal regardless of its <code>status</code>, so it is robust to the stale-status bug (#1388) rather than hanging on it.</p><p>Rejects only on two conditions: the reconcile fetch 404s (unknown or not-owned <code>runId</code> → <code>NOT_FOUND</code>), or <code>timeoutMs</code> elapses (<code>WORKFLOW_WAIT_TIMEOUT</code>). Both paths remove the listener and clear the timer, so there is no leak.</p><h4 id="parameters-11" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-11" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="runid" tabindex="-1">runId <a class="header-anchor" href="#runid" aria-label="Permalink to “runId”">​</a></h5><p><code>string</code></p><h5 id="options-11" tabindex="-1">options? <a class="header-anchor" href="#options-11" aria-label="Permalink to “options?”">​</a></h5><p><a href="./WaitForWorkflowOptions.html"><code>WaitForWorkflowOptions</code></a></p><h4 id="returns-11" tabindex="-1">Returns <a class="header-anchor" href="#returns-11" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./WaitForWorkflowResult.html"><code>WaitForWorkflowResult</code></a>&gt;</p>',140)])])}const m=a(s,[["render",l]]);export{u as __pageData,m as default};
